package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class CSVParserTest {

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String csvContent = "a,b,c\n1,2,3";
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMock = mockStatic(Assertions.class)) {
            // No exception thrown by Assertions.notNull
            assertionsMock.when(() -> Assertions.notNull(csvContent, "string")).thenCallRealMethod();
            assertionsMock.when(() -> Assertions.notNull(format, "format")).thenCallRealMethod();

            CSVParser parser = CSVParser.parse(csvContent, format);

            assertNotNull(parser);
            assertEquals(format, parser.format);
            assertFalse(parser.isClosed());
        }
    }

    @Test
    void testParse_withNullString_throwsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMock = mockStatic(Assertions.class)) {
            assertionsMock.when(() -> Assertions.notNull(null, "string")).thenThrow(new NullPointerException("string"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(null, format));
            assertEquals("string", ex.getMessage());
        }
    }

    @Test
    void testParse_withNullFormat_throwsNullPointerException() {
        String csvContent = "a,b,c";

        try (MockedStatic<Assertions> assertionsMock = mockStatic(Assertions.class)) {
            assertionsMock.when(() -> Assertions.notNull(csvContent, "string")).thenCallRealMethod();
            assertionsMock.when(() -> Assertions.notNull(null, "format")).thenThrow(new NullPointerException("format"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(csvContent, null));
            assertEquals("format", ex.getMessage());
        }
    }
}
